package online.yudream.base.infra.platform.wiki.impl;
import lombok.RequiredArgsConstructor; import online.yudream.base.domain.platform.wiki.aggregate.WikiPageVersion; import online.yudream.base.domain.platform.wiki.repo.WikiPageVersionRepo; import online.yudream.base.domain.shared.IdGenerator; import online.yudream.base.infra.platform.wiki.dataobj.WikiPageVersionDO; import online.yudream.base.infra.platform.wiki.mapper.WikiInfraMapper; import org.springframework.data.domain.Sort; import org.springframework.data.mongodb.core.MongoTemplate; import org.springframework.data.mongodb.core.query.Criteria; import org.springframework.data.mongodb.core.query.Query; import org.springframework.stereotype.Service; import java.time.LocalDateTime; import java.util.*;
@Service @RequiredArgsConstructor public class WikiPageVersionRepoImpl implements WikiPageVersionRepo {private final MongoTemplate mongo;private final IdGenerator ids;public WikiPageVersion save(WikiPageVersion v){WikiPageVersionDO d=WikiInfraMapper.version(v);if(d.getId()==null){d.setId(ids.nextId());d.setCreateTime(LocalDateTime.now());}d.setUpdateTime(LocalDateTime.now());return WikiInfraMapper.version(mongo.save(d));}public Optional<WikiPageVersion> findById(Long id){return Optional.ofNullable(WikiInfraMapper.version(mongo.findById(id,WikiPageVersionDO.class)));}public Optional<WikiPageVersion> findLatest(Long id){return Optional.ofNullable(WikiInfraMapper.version(mongo.findOne(Query.query(Criteria.where("nodeId").is(id)).with(Sort.by(Sort.Direction.DESC,"revision")),WikiPageVersionDO.class)));}}
